import { Inference, Page } from "../../../v1/parsing/common/index.js";
import { InvoiceSplitterV1Document } from "./invoiceSplitterV1Document.js";
/**
 * Invoice Splitter API version 1 inference prediction.
 */
export class InvoiceSplitterV1 extends Inference {
    constructor(rawPrediction) {
        super(rawPrediction);
        /** The endpoint's name. */
        this.endpointName = "invoice_splitter";
        /** The endpoint's version. */
        this.endpointVersion = "1";
        /** The document's pages. */
        this.pages = [];
        this.prediction = new InvoiceSplitterV1Document(rawPrediction["prediction"]);
        rawPrediction["pages"].forEach((page) => {
            if (page.prediction !== undefined && page.prediction !== null &&
                Object.keys(page.prediction).length > 0) {
                this.pages.push(new Page(InvoiceSplitterV1Document, page, page["id"], page["orientation"]));
            }
        });
    }
}
